package com.knoxhack.echostationfall.registry;
import com.knoxhack.echocore.api.EchoCoreServices; import com.knoxhack.echostationfall.EchoStationfall; import com.knoxhack.echostationfall.progression.*; import com.knoxhack.echostationfall.world.*; import com.knoxhack.echoorbitalremnants.suit.SuitState; import java.util.List; import net.minecraft.core.BlockPos; import net.minecraft.network.chat.Component; import net.minecraft.server.level.*; import net.minecraft.world.*; import net.minecraft.world.entity.*; import net.minecraft.world.entity.player.Player; import net.minecraft.world.item.ItemStack; import net.minecraft.world.level.Level; import net.minecraft.world.level.block.*; import net.minecraft.world.level.block.state.BlockState; import net.minecraft.world.level.material.MapColor; import net.minecraft.world.phys.BlockHitResult; import net.neoforged.bus.api.IEventBus; import net.neoforged.neoforge.registries.*;
public final class ModBlocks { public static final DeferredRegister.Blocks BLOCKS=DeferredRegister.createBlocks(EchoStationfall.MODID); public static final DeferredBlock<Block> STATIONFALL_PLATING=metal("stationfall_plating",MapColor.COLOR_GRAY), STATIONFALL_WALL_PANEL=metal("stationfall_wall_panel",MapColor.COLOR_BLACK); public static final DeferredBlock<Block> CONTAINMENT_POD=BLOCKS.registerBlock("containment_pod",ContainmentPodBlock::new,p->p.mapColor(MapColor.COLOR_LIGHT_BLUE).strength(4,8).sound(SoundType.METAL).lightLevel(s->3)); public static final DeferredBlock<Block> STATION_POWER_NODE=BLOCKS.registerBlock("station_power_node",StationPowerNodeBlock::new,p->p.mapColor(MapColor.COLOR_RED).strength(4,8).sound(SoundType.METAL).lightLevel(s->8)); public static final DeferredBlock<Block> PRESSURE_DOOR=BLOCKS.registerBlock("pressure_door",PressureDoorBlock::new,p->p.mapColor(MapColor.METAL).strength(5,12).sound(SoundType.METAL)); public static final DeferredBlock<Block> DAMAGED_AIRLOCK=BLOCKS.registerBlock("damaged_airlock",DamagedAirlockBlock::new,p->p.mapColor(MapColor.METAL).strength(5,12).sound(SoundType.METAL)); public static final DeferredBlock<Block> HULL_BREACH=BLOCKS.registerBlock("hull_breach",HullBreachBlock::new,p->p.mapColor(MapColor.COLOR_LIGHT_BLUE).strength(1.5F,3).sound(SoundType.METAL).noOcclusion()); public static final DeferredBlock<Block> CREW_LOG_TERMINAL=BLOCKS.registerBlock("crew_log_terminal",CrewLogTerminalBlock::new,p->p.mapColor(MapColor.COLOR_BLUE).strength(3,6).sound(SoundType.METAL).lightLevel(s->5)); public static final DeferredBlock<Block> DATA_CORE_TERMINAL=BLOCKS.registerBlock("data_core_terminal",DataCoreTerminalBlock::new,p->p.mapColor(MapColor.COLOR_PURPLE).strength(4,8).sound(SoundType.METAL).lightLevel(s->6)); public static final DeferredBlock<Block> COMMAND_CONSOLE=BLOCKS.registerBlock("command_console",CommandConsoleBlock::new,p->p.mapColor(MapColor.COLOR_RED).strength(6,12).sound(SoundType.METAL).lightLevel(s->7)); public static final DeferredBlock<Block> CRACKED_OBSERVATION_GLASS=BLOCKS.registerBlock("cracked_observation_glass",ObservationGlassBlock::new,p->p.mapColor(MapColor.COLOR_CYAN).strength(.8F,1.5F).sound(SoundType.GLASS).noOcclusion().isValidSpawn((s,l,pos,t)->false)); public static final DeferredBlock<Block> CORRUPTED_HYDROPONIC_GROWTH=BLOCKS.registerBlock("corrupted_hydroponic_growth",CorruptedHydroponicGrowthBlock::new,p->p.mapColor(MapColor.PLANT).strength(.8F).sound(SoundType.GRASS).noOcclusion()); public static final List<DeferredBlock<Block>> ALL_BLOCKS=List.of(STATIONFALL_PLATING,STATIONFALL_WALL_PANEL,STATION_POWER_NODE,PRESSURE_DOOR,DAMAGED_AIRLOCK,HULL_BREACH,CREW_LOG_TERMINAL,DATA_CORE_TERMINAL,COMMAND_CONSOLE,CRACKED_OBSERVATION_GLASS,CORRUPTED_HYDROPONIC_GROWTH,CONTAINMENT_POD); private ModBlocks(){} public static void register(IEventBus b){BLOCKS.register(b);} private static DeferredBlock<Block> metal(String n,MapColor c){return BLOCKS.registerSimpleBlock(n,p->p.mapColor(c).strength(4,8).sound(SoundType.METAL));} private static StationSection section(BlockPos p){return StationSection.fromPosition(p);} private static void consume(Player p,InteractionHand h){if(!p.hasInfiniteMaterials())p.getItemInHand(h).shrink(1);} private static void give(Player p,ItemStack s){ItemStack c=s.copy(); if(!p.getInventory().add(c))p.drop(c,false);} private static void spawnNear(ServerLevel l,BlockPos p,EntityType<? extends Mob> t,Player target){Entity e=t.create(l,EntitySpawnReason.EVENT); if(e instanceof Mob m){m.setPos(p.getX()+.5,p.getY()+1,p.getZ()+.5);m.setTarget(target);l.addFreshEntity(m);}}
 public static class StationPowerNodeBlock extends Block{public StationPowerNodeBlock(Properties p){super(p);} protected InteractionResult useItemOn(ItemStack stack,BlockState bs,Level level,BlockPos pos,Player player,InteractionHand hand,BlockHitResult hit){if(level.isClientSide())return InteractionResult.SUCCESS; if(!(level instanceof ServerLevel sl))return InteractionResult.CONSUME; StationSection s=section(pos); StationPowerState st=null; if(stack.is(ModItems.STATION_BATTERY.get())){st=player.isShiftKeyDown()?StationPowerState.OVERLOADED:StationPowerState.STABLE;consume(player,hand);} else if(stack.is(ModItems.HULL_CUTTER.get())){st=StationPowerState.PARTIAL; SuitState suit=SuitState.get(player); suit.compromisePressure(12+s.hazardIntensity()); suit.save(player); SignalPanicState.get(player).gain(player,10+s.hazardIntensity());} if(st==null){player.sendSystemMessage(Component.literal("ECHO-7 // "+s.displayName()+" node expects Station Battery. Hull Cutter can force partial power."));return InteractionResult.CONSUME;} StationfallStationState.get(sl).setPower(s,st); StationfallProgress.get(player).setSectionPower(player,s,st); if(s==StationSection.ENGINEERING_DECK&&st.stableOrBetter())advanceObjective(sl,player,StationfallObjective.ENGINEERING_BREAKER,pos); player.sendSystemMessage(Component.literal("ECHO-7 // "+s.displayName()+" power state: "+st.displayName()+".")); if(st==StationPowerState.OVERLOADED){SignalPanicState.get(player).gain(player,15); spawnNear(sl,pos.above(),ModEntities.MAINTENANCE_DRONE.get(),player);} return InteractionResult.SUCCESS_SERVER;} protected InteractionResult useWithoutItem(BlockState st,Level l,BlockPos p,Player pl,BlockHitResult hit){if(!l.isClientSide()&&l instanceof ServerLevel sl){StationSection s=section(p);pl.sendSystemMessage(Component.literal("ECHO-7 // "+s.displayName()+" power: "+StationfallStationState.get(sl).powerState(s).displayName()+"."));} return InteractionResult.SUCCESS_SERVER;}}
 public static class PressureDoorBlock extends Block{public PressureDoorBlock(Properties p){super(p);} protected InteractionResult useWithoutItem(BlockState s,Level l,BlockPos p,Player pl,BlockHitResult h){return operate(l,p,pl);} protected InteractionResult useItemOn(ItemStack stack,BlockState s,Level l,BlockPos p,Player pl,InteractionHand hand,BlockHitResult h){if(stack.is(ModItems.HULL_CUTTER.get())&&!l.isClientSide()){l.setBlock(p,Blocks.AIR.defaultBlockState(),3);SignalPanicState.get(pl).gain(pl,8);pl.sendSystemMessage(Component.literal("ECHO-7 // Door lock severed. Pressure model no longer trusts this corridor."));return InteractionResult.SUCCESS_SERVER;} return operate(l,p,pl);} protected InteractionResult operate(Level l,BlockPos p,Player pl){if(l.isClientSide())return InteractionResult.SUCCESS; StationSection s=section(p); if(l instanceof ServerLevel sl && StationfallStationState.get(sl).doorUnlocked(s)){l.setBlock(p,Blocks.AIR.defaultBlockState(),3);pl.sendSystemMessage(Component.literal("ECHO-7 // "+s.displayName()+" pressure door cycled."));return InteractionResult.SUCCESS_SERVER;} SignalPanicState.get(pl).gain(pl,6);pl.sendSystemMessage(Component.literal("FALSE ECHO // Door "+s.displayName()+" says SAFE. Door refuses to agree."));return InteractionResult.CONSUME;}}
 public static final class DamagedAirlockBlock extends PressureDoorBlock{public DamagedAirlockBlock(Properties p){super(p);} protected InteractionResult operate(Level l,BlockPos p,Player pl){if(!l.isClientSide()){SuitState suit=SuitState.get(pl);suit.compromisePressure(10);suit.drainOxygen(8);suit.save(pl);SignalPanicState.get(pl).gain(pl,8);} return super.operate(l,p,pl);}}
 public static final class HullBreachBlock extends Block{public HullBreachBlock(Properties p){super(p);} protected InteractionResult useItemOn(ItemStack stack,BlockState st,Level l,BlockPos p,Player pl,InteractionHand hand,BlockHitResult h){if(l.isClientSide())return InteractionResult.SUCCESS; StationSection s=section(p); if(stack.is(ModItems.PRESSURE_SEAL_KIT.get())){if(l instanceof ServerLevel sl)StationfallStationState.get(sl).setBreachRepaired(s,true); SuitState suit=SuitState.get(pl);suit.applySealantPatch();suit.save(pl);consume(pl,hand);l.setBlock(p,ModBlocks.STATIONFALL_WALL_PANEL.get().defaultBlockState(),3);pl.sendSystemMessage(Component.literal("ECHO-7 // Hull breach sealed. "+s.displayName()+" pressure stabilizing."));return InteractionResult.SUCCESS_SERVER;} SuitState suit=SuitState.get(pl);suit.compromisePressure(14+s.hazardIntensity());suit.drainOxygen(6);suit.save(pl);SignalPanicState.get(pl).gain(pl,8+s.hazardIntensity());pl.sendSystemMessage(Component.literal("ECHO-7 // Pressure leak detected. Apply Pressure Seal Kit."));return InteractionResult.CONSUME;}}
 public static final class CrewLogTerminalBlock extends Block{public CrewLogTerminalBlock(Properties p){super(p);} protected InteractionResult useWithoutItem(BlockState st,Level l,BlockPos p,Player pl,BlockHitResult h){if(l.isClientSide())return InteractionResult.SUCCESS; StationSection s=section(p); StationfallProgress pr=StationfallProgress.get(pl); if(!pr.logDecoded(s)){pr.decodeLog(pl,s); if(l instanceof ServerLevel sl){StationfallStationState.get(sl).setLogDecoded(s,true); if(s==StationSection.MEDICAL_WING)advanceObjective(sl,pl,StationfallObjective.MEDICAL_MANIFEST,p);} give(pl,new ItemStack(ModItems.CREW_LOG_TABLET.get()));} for(String line:StationLore.crewLog(s))pl.sendSystemMessage(Component.literal("CREW LOG // "+line)); return InteractionResult.SUCCESS_SERVER;}}
 public static final class DataCoreTerminalBlock extends Block{public DataCoreTerminalBlock(Properties p){super(p);} protected InteractionResult useWithoutItem(BlockState st,Level l,BlockPos p,Player pl,BlockHitResult h){if(!l.isClientSide()){StationfallProgress pr=StationfallProgress.get(pl); if(!pr.aiOverrideObtained()){pr.markAiOverrideObtained(pl);give(pl,new ItemStack(ModItems.AI_OVERRIDE_CHIP.get())); if(pl instanceof ServerPlayer sp)EchoCoreServices.unlockArchive(sp,"echostationfall:stationfall_data_core_override"); pl.sendSystemMessage(Component.literal("ECHO-7 // AI Override Chip recovered. The station recognized my voice before I spoke."));} else pl.sendSystemMessage(Component.literal("ECHO-7 // AI Override already synchronized. Proceed to the Command Module console."));} return InteractionResult.SUCCESS_SERVER;}}
 public static final class CommandConsoleBlock extends Block{public CommandConsoleBlock(Properties p){super(p);} protected InteractionResult useWithoutItem(BlockState st,Level l,BlockPos p,Player pl,BlockHitResult h){if(l.isClientSide())return InteractionResult.SUCCESS; if(!(pl instanceof ServerPlayer sp)||!(l instanceof ServerLevel sl))return InteractionResult.CONSUME; StationfallProgress pr=StationfallProgress.get(pl); StationfallStationState ss=StationfallStationState.get(sl); if(pr.bossDefeated()||ss.bossDefeated()){ModEntities.StationMotherEntity.grantRewards(sp);return InteractionResult.SUCCESS_SERVER;} if(ss.bossActive()){pl.sendSystemMessage(Component.literal("STATION MOTHER // Emergency protocol already active. Finish the encounter."));return InteractionResult.CONSUME;} if(!pr.allObjectivesComplete()&&!pl.hasInfiniteMaterials()){pl.sendSystemMessage(Component.literal("STATION MOTHER // Section stabilization incomplete. Finish TRACK SECTION objectives before Command upload."));SignalPanicState.get(pl).gain(pl,8);return InteractionResult.CONSUME;} if(!pr.aiOverrideObtained()&&!pl.hasInfiniteMaterials()){pl.sendSystemMessage(Component.literal("STATION MOTHER // Override key absent. Preservation remains mandatory. Recover the Data Core override first."));SignalPanicState.get(pl).gain(pl,12);return InteractionResult.CONSUME;} Entity e=ModEntities.STATION_MOTHER.get().create(sl,EntitySpawnReason.EVENT); if(e instanceof ModEntities.StationMotherEntity m){m.setPos(p.getX()+.5,p.getY()+2,p.getZ()+.5);sl.addFreshEntity(m);ss.startBoss();pl.sendSystemMessage(Component.literal("STATION MOTHER // Emergency protocol accepted. Crew preservation resuming."));return InteractionResult.SUCCESS_SERVER;} return InteractionResult.CONSUME;}}
 public static final class ContainmentPodBlock extends Block{public ContainmentPodBlock(Properties p){super(p);} protected InteractionResult useWithoutItem(BlockState st,Level l,BlockPos p,Player pl,BlockHitResult h){if(!l.isClientSide()&&l instanceof ServerLevel sl){advanceObjective(sl,pl,StationfallObjective.CONTAINMENT_RECORDS,p);pl.sendSystemMessage(Component.literal("ECHO-7 // Pod record queried. Occupant names are blank by policy."));}return InteractionResult.SUCCESS_SERVER;}}
 public static final class ObservationGlassBlock extends Block{public ObservationGlassBlock(Properties p){super(p);} protected InteractionResult useWithoutItem(BlockState st,Level l,BlockPos p,Player pl,BlockHitResult h){if(!l.isClientSide()&&l instanceof ServerLevel sl){advanceObjective(sl,pl,StationfallObjective.OBSERVATION_ANTENNA,p);pl.sendSystemMessage(Component.literal("ECHO-7 // Observation antenna node aligned. Return vector noise reduced."));}return InteractionResult.SUCCESS_SERVER;}}
 public static final class CorruptedHydroponicGrowthBlock extends Block{public CorruptedHydroponicGrowthBlock(Properties p){super(p);} protected InteractionResult useWithoutItem(BlockState st,Level l,BlockPos p,Player pl,BlockHitResult h){if(!l.isClientSide()&&l instanceof ServerLevel sl){advanceObjective(sl,pl,StationfallObjective.HYDROPONICS_PURGE,p);l.setBlock(p,Blocks.AIR.defaultBlockState(),3);pl.sendSystemMessage(Component.literal("ECHO-7 // Growth cluster purged. Atmosphere remains mostly hostile."));}return InteractionResult.SUCCESS_SERVER;} public void stepOn(Level l,BlockPos p,BlockState st,Entity e){super.stepOn(l,p,st,e); if(!l.isClientSide()&&e instanceof Player pl&&StationfallCooldown.ready(pl,"block.pulse.hydroponic_growth",40)){SignalPanicState.get(pl).gain(pl,3);SuitState suit=SuitState.get(pl);suit.drainOxygen(1);suit.save(pl);}}}
 private static void advanceObjective(ServerLevel level,Player player,StationfallObjective objective,BlockPos pos){StationfallProgress progress=StationfallProgress.get(player); boolean wasComplete=progress.objectiveComplete(objective); if(progress.recordObjectiveStep(player,objective,objective.key()+"@"+pos.getX()+","+pos.getY()+","+pos.getZ())){if(progress.objectiveComplete(objective)){StationfallStationState.get(level).setObjectiveComplete(objective,true); player.sendSystemMessage(Component.literal("ECHO-7 // Objective complete: "+objective.title()+"."));}else player.sendSystemMessage(Component.literal("ECHO-7 // Objective progress: "+objective.title()+" "+progress.objectiveStepCount(objective)+"/"+objective.targetSteps()+"."));}else if(wasComplete)player.sendSystemMessage(Component.literal("ECHO-7 // Objective already complete: "+objective.title()+"."));}
}
